   VERSION 13 — FULL REPLACE
   ========================= */

/* reset */
* { box-sizing: border-box; }
html, body { height: 100%; }
body { margin: 0; }

/* ====== theme tokens ====== */
:root{
  --ink: #2a2a2a;
  --muted: #6b6b6b;

  --stone: #e9e5dc;
  --paper: #f2efe6;

  /* geometry */
  --corniceH: 96px;
  --stepH: 160px;

  --colW: 86px;
  --upperPlinthW: 120px;
  --lowerPlinthW: 260px;

  --colGap: 26px;

  --capH: 28px;
  --upperPlinthH: 22px;
  --lowerPlinthH: 34px;
}

/* ====== base typography ====== */
body{
  font: 16px/1.6 system-ui, -apple-system, "Segoe UI", Roboto, Arial, sans-serif;
  color: var(--ink);
  background: var(--paper);
}

h1{
  margin: 0 0 12px;
  font-size: 30px;
  letter-spacing: .4px;
}

p{ margin: 10px 0; color: var(--muted); }
a{ color: #0b4f6c; text-decoration: none; }
a:hover{ text-decoration: underline; }

/* layout */
main{
  max-width: 980px;
  margin: 0 auto;
  padding: 32px 20px;
}

header{ text-align: center; }

/* =========================
   PUBLICATIONS — PORTAL
   ========================= */

body.publications-directory{
  background-color: var(--paper);

  background-image:

  /* cornice */
  linear-gradient(180deg, rgba(255,255,255,.85), rgba(0,0,0,.12)),
  repeating-linear-gradient(90deg, rgba(0,0,0,.06) 0 10px, rgba(255,255,255,.18) 10px 20px),

  /* steps */
  linear-gradient(180deg, rgba(0,0,0,.14), rgba(255,255,255,.35)),
  repeating-linear-gradient(0deg, rgba(0,0,0,.06) 0 2px, rgba(255,255,255,.16) 2px 14px),

  /* LEFT PAIR — LOWER PLINTH */
  linear-gradient(180deg, rgba(255,255,255,.55), rgba(0,0,0,.18)),

  /* RIGHT PAIR — LOWER PLINTH */
  linear-gradient(180deg, rgba(255,255,255,.55), rgba(0,0,0,.18)),

  /* LEFT OUTER COLUMN */
  linear-gradient(180deg, rgba(255,255,255,.70), rgba(0,0,0,.10)),
  /* LEFT INNER COLUMN */
  linear-gradient(180deg, rgba(255,255,255,.70), rgba(0,0,0,.10)),

  /* RIGHT INNER COLUMN */
  linear-gradient(180deg, rgba(255,255,255,.70), rgba(0,0,0,.10)),
  /* RIGHT OUTER COLUMN */
  linear-gradient(180deg, rgba(255,255,255,.70), rgba(0,0,0,.10)),

  /* parchment */
  linear-gradient(180deg, rgba(255,255,255,.45), rgba(0,0,0,.04));

  background-size:
  100% var(--corniceH),
  100% var(--corniceH),

  100% var(--stepH),
  100% var(--stepH),

  var(--lowerPlinthW) var(--lowerPlinthH),
  var(--lowerPlinthW) var(--lowerPlinthH),

  var(--colW) calc(100vh - var(--corniceH) - var(--stepH)),
  var(--colW) calc(100vh - var(--corniceH) - var(--stepH)),

  var(--colW) calc(100vh - var(--corniceH) - var(--stepH)),
  var(--colW) calc(100vh - var(--corniceH) - var(--stepH)),

  100% 100%;

  background-position:
  0 0,
  0 0,

  0 100%,
  0 100%,

  calc(var(--lowerPlinthW) * .25) calc(100% - var(--stepH)),
  calc(100% - var(--lowerPlinthW) * 1.25) calc(100% - var(--stepH)),

  calc(var(--lowerPlinthW) * .25 + 40px) var(--corniceH),
  calc(var(--lowerPlinthW) * .25 + 40px + var(--colW) + var(--colGap)) var(--corniceH),

  calc(100% - var(--lowerPlinthW) * .25 - 40px - var(--colW) - var(--colGap)) var(--corniceH),
  calc(100% - var(--lowerPlinthW) * .25 - 40px) var(--corniceH),

  0 0;

  background-repeat: no-repeat;
}

/* ====== overlays: fluting, caps, upper plinths ====== */
body.publications-directory::before{
  content: "";
  position: fixed;
  inset: 0;
  pointer-events: none;

  background-image:

  /* LEFT OUTER */
  repeating-linear-gradient(90deg, rgba(0,0,0,.06) 0 7px, rgba(255,255,255,.18) 7px 14px),
  linear-gradient(180deg, rgba(255,255,255,.65), rgba(0,0,0,.12)),
  linear-gradient(180deg, rgba(255,255,255,.55), rgba(0,0,0,.18)),

  /* LEFT INNER */
  repeating-linear-gradient(90deg, rgba(0,0,0,.06) 0 7px, rgba(255,255,255,.18) 7px 14px),
  linear-gradient(180deg, rgba(255,255,255,.65), rgba(0,0,0,.12)),
  linear-gradient(180deg, rgba(255,255,255,.55), rgba(0,0,0,.18)),

  /* RIGHT INNER */
  repeating-linear-gradient(90deg, rgba(0,0,0,.06) 0 7px, rgba(255,255,255,.18) 7px 14px),
  linear-gradient(180deg, rgba(255,255,255,.65), rgba(0,0,0,.12)),
  linear-gradient(180deg, rgba(255,255,255,.55), rgba(0,0,0,.18)),

  /* RIGHT OUTER */
  repeating-linear-gradient(90deg, rgba(0,0,0,.06) 0 7px, rgba(255,255,255,.18) 7px 14px),
  linear-gradient(180deg, rgba(255,255,255,.65), rgba(0,0,0,.12)),
  linear-gradient(180deg, rgba(255,255,255,.55), rgba(0,0,0,.18));

  background-size:
  var(--colW) calc(100vh - var(--corniceH) - var(--stepH)),
  var(--upperPlinthW) var(--capH),
  var(--upperPlinthW) var(--upperPlinthH),

  var(--colW) calc(100vh - var(--corniceH) - var(--stepH)),
  var(--upperPlinthW) var(--capH),
  var(--upperPlinthW) var(--upperPlinthH),

  var(--colW) calc(100vh - var(--corniceH) - var(--stepH)),
  var(--upperPlinthW) var(--capH),
  var(--upperPlinthW) var(--upperPlinthH),

  var(--colW) calc(100vh - var(--corniceH) - var(--stepH)),
  var(--upperPlinthW) var(--capH),
  var(--upperPlinthW) var(--upperPlinthH);

  background-position:
  calc(var(--lowerPlinthW) * .25 + 40px) var(--corniceH),
  calc(var(--lowerPlinthW) * .25 + 23px) var(--corniceH),
  calc(var(--lowerPlinthW) * .25 + 23px) calc(100% - var(--stepH) - var(--upperPlinthH)),

  calc(var(--lowerPlinthW) * .25 + 40px + var(--colW) + var(--colGap)) var(--corniceH),
  calc(var(--lowerPlinthW) * .25 + 23px + var(--colW) + var(--colGap)) var(--corniceH),
  calc(var(--lowerPlinthW) * .25 + 23px + var(--colW) + var(--colGap)) calc(100% - var(--stepH) - var(--upperPlinthH)),

  calc(100% - var(--lowerPlinthW) * .25 - 40px - var(--colW) - var(--colGap)) var(--corniceH),
  calc(100% - var(--lowerPlinthW) * .25 - 23px - var(--colW) - var(--colGap)) var(--corniceH),
  calc(100% - var(--lowerPlinthW) * .25 - 23px - var(--colW) - var(--colGap)) calc(100% - var(--stepH) - var(--upperPlinthH)),

  calc(100% - var(--lowerPlinthW) * .25 - 40px) var(--corniceH),
  calc(100% - var(--lowerPlinthW) * .25 - 23px) var(--corniceH),
  calc(100% - var(--lowerPlinthW) * .25 - 23px) calc(100% - var(--stepH) - var(--upperPlinthH));

  background-repeat: no-repeat;
}

/* content centering */
body.publications-directory main{
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  padding-top: calc(var(--corniceH) + 24px);
  padding-bottom: calc(var(--stepH) + 24px);
  position: relative;
  z-index: 1;
}

