/* =========================
   Rodzaki — assets/style.css
   FULL REPLACEMENT
   VERSION 17
========================= */

/* ===== reset ===== */
*,
*::before,
*::after { box-sizing: border-box; }

html, body { height: 100%; }
body { margin: 0; }

/* ===== theme tokens ===== */
:root{
  --ink: #2a2a2a;
  --muted: #6b6b6b;
  --line: rgba(0,0,0,.12);

  --paper: #f2efe6;
  --stone: #e9e5dc;
  --shadow: rgba(0,0,0,.18);

  /* portal geometry */
  --corniceH: 96px;
  --stepH: 160px;

  /* column geometry */
  --edgePad: 28px;   /* outer columns do NOT touch screen edge */
  --colW: 86px;
  --colGap: 26px;    /* gap between the two columns in a pair */

  /* plinth geometry */
  --pairBaseH: 42px; /* lower plinth (shared per pair) */
  --pairBaseInsetFromStepTop: 0px; /* keep at step-plane; adjust if needed */
  --pairBaseOverhang: 30px; /* how much wider than pair footprint */
  --capH: 26px;      /* top widening piece height */
  --capOverhang: 20px; /* how much wider than shaft */
  --upperPlinthH: 28px;
  --upperPlinthOverhang: 14px;

  /* computed helpers (do not edit) */
  --shaftH: calc(100vh - var(--corniceH) - var(--stepH));
  --pairW: calc(var(--colW) * 2 + var(--colGap));
}

/* ===== base typography ===== */
body{
  font: 16px/1.6 system-ui, -apple-system, "Segoe UI", Roboto, Arial, sans-serif;
  color: var(--ink);
  background: var(--paper);
}

h1{
  margin: 0 0 12px;
  font-size: 30px;
  letter-spacing: .4px;
}
h2{
  margin-top: 32px;
  font-size: 18px;
  letter-spacing: .3px;
}
p{ margin: 10px 0; color: var(--muted); }
a{ color: #0b4f6c; text-decoration: none; }
a:hover{ text-decoration: underline; }

/* ===== layout ===== */
main{
  max-width: 980px;
  margin: 0 auto;
  padding: 32px 20px;
}
header{ text-align: center; }

/* directory links as calm entries */
.directory-links p{
  margin: 8px 0;
  font-size: 17px;
}

ul{
  margin: 10px auto;
  padding-left: 18px;
  color: var(--muted);
  text-align: left;
  display: inline-block;
}

/* ============================================================
   PUBLICATIONS — MUSEUM PORTAL (4 columns, identical; mirrored)
   Applies ONLY on publications directory body class
============================================================ */

body.publications-directory{
  color: var(--ink);
  background-color: var(--paper);

  /* Base layers: parchment + cornice + steps */
  background-image:
    /* 1) parchment */
    linear-gradient(180deg, rgba(255,255,255,.45), rgba(0,0,0,.04)),

    /* 2) cornice face */
    linear-gradient(180deg, rgba(255,255,255,.82), rgba(0,0,0,.12)),

    /* 3) cornice subtle banding */
    repeating-linear-gradient(90deg, rgba(0,0,0,.06) 0 10px, rgba(255,255,255,.16) 10px 20px),

    /* 4) steps tread */
    linear-gradient(180deg, rgba(0,0,0,.10), rgba(255,255,255,.30)),

    /* 5) steps riser stripes */
    repeating-linear-gradient(0deg, rgba(0,0,0,.06) 0 2px, rgba(255,255,255,.16) 2px 14px);

  background-size:
    /* parchment */ 100% 100%,
    /* cornice */ 100% var(--corniceH),
    /* banding */ 100% var(--corniceH),
    /* tread */ 100% var(--stepH),
    /* risers */ 100% var(--stepH);

  background-position:
    /* parchment */ 0 0,
    /* cornice */ 0 0,
    /* banding */ 0 0,
    /* tread */ 0 100%,
    /* risers */ 0 100%;

  background-repeat: no-repeat;
}

/* ---- architectural solids (shafts + plinths + caps) ----
   Done as ONE overlay so symmetry stays exact.
*/
body.publications-directory::before{
  content: "";
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 0;

  /* positions */
  --xOL: var(--edgePad);
  --xIL: calc(var(--edgePad) + var(--colW) + var(--colGap));
  --xIR: calc(100% - var(--edgePad) - var(--colW) - var(--colW) - var(--colGap));
  --xOR: calc(100% - var(--edgePad) - var(--colW));

  /* pair bases (shared per pair) */
  --pairLeftX: calc(var(--edgePad) + (var(--colW) / 2) - (var(--pairBaseOverhang) / 2));
  --pairRightX: calc(100% - var(--edgePad) - var(--pairW) + (var(--colW) / 2) - (var(--pairBaseOverhang) / 2));

  --pairBaseW: calc(var(--pairW) + var(--pairBaseOverhang));
  --pairBaseY: calc(100% - var(--stepH) - var(--pairBaseH) + var(--pairBaseInsetFromStepTop));

  /* upper plinth per column (individual; not touching) */
  --upW: calc(var(--colW) + var(--upperPlinthOverhang) * 2);
  --upH: var(--upperPlinthH);
  --upY: calc(var(--pairBaseY) - var(--upH) + 6px); /* visually nests into base plinth slightly */

  /* cap (capital) per column (individual; widened; rounded) */
  --capW: calc(var(--colW) + var(--capOverhang) * 2);
  --capY: calc(var(--corniceH) - var(--capH));

  /* shaft start/end */
  --shaftY: var(--corniceH);
  --shaftEndY: calc(100% - var(--stepH));
  --shaftH2: calc(var(--shaftEndY) - var(--shaftY));

  background-image:
    /* ===== pair base plinths (pill: left pair) ===== */
    radial-gradient(closest-side at 50% 50%, rgba(255,255,255,.60), rgba(0,0,0,.12)),
    radial-gradient(circle at left center, rgba(255,255,255,.55) 0 55%, rgba(0,0,0,.12) 56% 100%),
    radial-gradient(circle at right center, rgba(255,255,255,.55) 0 55%, rgba(0,0,0,.12) 56% 100%),

    /* ===== pair base plinths (pill: right pair) ===== */
    radial-gradient(closest-side at 50% 50%, rgba(255,255,255,.60), rgba(0,0,0,.12)),
    radial-gradient(circle at left center, rgba(255,255,255,.55) 0 55%, rgba(0,0,0,.12) 56% 100%),
    radial-gradient(circle at right center, rgba(255,255,255,.55) 0 55%, rgba(0,0,0,.12) 56% 100%),

    /* ===== upper plinths (4 individual pills) ===== */
    radial-gradient(closest-side at 50% 50%, rgba(255,255,255,.65), rgba(0,0,0,.13)),
    radial-gradient(circle at left center, rgba(255,255,255,.60) 0 55%, rgba(0,0,0,.13) 56% 100%),
    radial-gradient(circle at right center, rgba(255,255,255,.60) 0 55%, rgba(0,0,0,.13) 56% 100%),

    radial-gradient(closest-side at 50% 50%, rgba(255,255,255,.65), rgba(0,0,0,.13)),
    radial-gradient(circle at left center, rgba(255,255,255,.60) 0 55%, rgba(0,0,0,.13) 56% 100%),
    radial-gradient(circle at right center, rgba(255,255,255,.60) 0 55%, rgba(0,0,0,.13) 56% 100%),

    radial-gradient(closest-side at 50% 50%, rgba(255,255,255,.65), rgba(0,0,0,.13)),
    radial-gradient(circle at left center, rgba(255,255,255,.60) 0 55%, rgba(0,0,0,.13) 56% 100%),
    radial-gradient(circle at right center, rgba(255,255,255,.60) 0 55%, rgba(0,0,0,.13) 56% 100%),

    radial-gradient(closest-side at 50% 50%, rgba(255,255,255,.65), rgba(0,0,0,.13)),
    radial-gradient(circle at left center, rgba(255,255,255,.60) 0 55%, rgba(0,0,0,.13) 56% 100%),
    radial-gradient(circle at right center, rgba(255,255,255,.60) 0 55%, rgba(0,0,0,.13) 56% 100%),

    /* ===== column shafts (4 identical rectangles) ===== */
    linear-gradient(180deg, rgba(255,255,255,.72), rgba(0,0,0,.12)),
    linear-gradient(180deg, rgba(255,255,255,.72), rgba(0,0,0,.12)),
    linear-gradient(180deg, rgba(255,255,255,.72), rgba(0,0,0,.12)),
    linear-gradient(180deg, rgba(255,255,255,.72), rgba(0,0,0,.12)),

    /* ===== capitals (4 individual pills, widened, rounded) ===== */
    radial-gradient(closest-side at 50% 50%, rgba(255,255,255,.70), rgba(0,0,0,.14)),
    radial-gradient(circle at left center, rgba(255,255,255,.64) 0 55%, rgba(0,0,0,.14) 56% 100%),
    radial-gradient(circle at right center, rgba(255,255,255,.64) 0 55%, rgba(0,0,0,.14) 56% 100%),

    radial-gradient(closest-side at 50% 50%, rgba(255,255,255,.70), rgba(0,0,0,.14)),
    radial-gradient(circle at left center, rgba(255,255,255,.64) 0 55%, rgba(0,0,0,.14) 56% 100%),
    radial-gradient(circle at right center, rgba(255,255,255,.64) 0 55%, rgba(0,0,0,.14) 56% 100%),

    radial-gradient(closest-side at 50% 50%, rgba(255,255,255,.70), rgba(0,0,0,.14)),
    radial-gradient(circle at left center, rgba(255,255,255,.64) 0 55%, rgba(0,0,0,.14) 56% 100%),
    radial-gradient(circle at right center, rgba(255,255,255,.64) 0 55%, rgba(0,0,0,.14) 56% 100%),

    radial-gradient(closest-side at 50% 50%, rgba(255,255,255,.70), rgba(0,0,0,.14)),
    radial-gradient(circle at left center, rgba(255,255,255,.64) 0 55%, rgba(0,0,0,.14) 56% 100%),
    radial-gradient(circle at right center, rgba(255,255,255,.64) 0 55%, rgba(0,0,0,.14) 56% 100%);

  /* sizes per layer */
  background-size:
    /* left pair base (center + ends) */
    var(--pairBaseW) var(--pairBaseH),
    var(--pairBaseW) var(--pairBaseH),
    var(--pairBaseW) var(--pairBaseH),

    /* right pair base (center + ends) */
    var(--pairBaseW) var(--pairBaseH),
    var(--pairBaseW) var(--pairBaseH),
    var(--pairBaseW) var(--pairBaseH),

    /* upper plinth OL (center + ends) */
    var(--upW) var(--upH),
    var(--upW) var(--upH),
    var(--upW) var(--upH),

    /* upper plinth IL */
    var(--upW) var(--upH),
    var(--upW) var(--upH),
    var(--upW) var(--upH),

    /* upper plinth IR */
    var(--upW) var(--upH),
    var(--upW) var(--upH),
    var(--upW) var(--upH),

    /* upper plinth OR */
    var(--upW) var(--upH),
    var(--upW) var(--upH),
    var(--upW) var(--upH),

    /* shafts (4) */
    var(--colW) var(--shaftH2),
    var(--colW) var(--shaftH2),
    var(--colW) var(--shaftH2),
    var(--colW) var(--shaftH2),

    /* capitals OL */
    var(--capW) var(--capH),
    var(--capW) var(--capH),
    var(--capW) var(--capH),

    /* capitals IL */
    var(--capW) var(--capH),
    var(--capW) var(--capH),
    var(--capW) var(--capH),

    /* capitals IR */
    var(--capW) var(--capH),
    var(--capW) var(--capH),
    var(--capW) var(--capH),

    /* capitals OR */
    var(--capW) var(--capH),
    var(--capW) var(--capH),
    var(--capW) var(--capH);

  /* positions per layer */
  background-position:
    /* left pair base */
    var(--pairLeftX) var(--pairBaseY),
    var(--pairLeftX) var(--pairBaseY),
    var(--pairLeftX) var(--pairBaseY),

    /* right pair base */
    var(--pairRightX) var(--pairBaseY),
    var(--pairRightX) var(--pairBaseY),
    var(--pairRightX) var(--pairBaseY),

    /* upper plinth OL */
    calc(var(--xOL) - var(--upperPlinthOverhang)) var(--upY),
    calc(var(--xOL) - var(--upperPlinthOverhang)) var(--upY),
    calc(var(--xOL) - var(--upperPlinthOverhang)) var(--upY),

    /* upper plinth IL */
    calc(var(--xIL) - var(--upperPlinthOverhang)) var(--upY),
    calc(var(--xIL) - var(--upperPlinthOverhang)) var(--upY),
    calc(var(--xIL) - var(--upperPlinthOverhang)) var(--upY),

    /* upper plinth IR */
    calc(var(--xIR) - var(--upperPlinthOverhang)) var(--upY),
    calc(var(--xIR) - var(--upperPlinthOverhang)) var(--upY),
    calc(var(--xIR) - var(--upperPlinthOverhang)) var(--upY),

    /* upper plinth OR */
    calc(var(--xOR) - var(--upperPlinthOverhang)) var(--upY),
    calc(var(--xOR) - var(--upperPlinthOverhang)) var(--upY),
    calc(var(--xOR) - var(--upperPlinthOverhang)) var(--upY),

    /* shafts */
    var(--xOL) var(--shaftY),
    var(--xIL) var(--shaftY),
    var(--xIR) var(--shaftY),
    var(--xOR) var(--shaftY),

    /* capitals OL */
    calc(var(--xOL) - var(--capOverhang)) var(--capY),
    calc(var(--xOL) - var(--capOverhang)) var(--capY),
    calc(var(--xOL) - var(--capOverhang)) var(--capY),

    /* capitals IL */
    calc(var(--xIL) - var(--capOverhang)) var(--capY),
    calc(var(--xIL) - var(--capOverhang)) var(--capY),
    calc(var(--xIL) - var(--capOverhang)) var(--capY),

    /* capitals IR */
    calc(var(--xIR) - var(--capOverhang)) var(--capY),
    calc(var(--xIR) - var(--capOverhang)) var(--capY),
    calc(var(--xIR) - var(--capOverhang)) var(--capY),

    /* capitals OR */
    calc(var(--xOR) - var(--capOverhang)) var(--capY),
    calc(var(--xOR) - var(--capOverhang)) var(--capY),
    calc(var(--xOR) - var(--capOverhang)) var(--capY);

  background-repeat: no-repeat;
  opacity: .97;
}

/* ---- fluting overlay (same 4 columns; identical; aligned) ---- */
body.publications-directory::after{
  content: "";
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 0;

  --xOL: var(--edgePad);
  --xIL: calc(var(--edgePad) + var(--colW) + var(--colGap));
  --xIR: calc(100% - var(--edgePad) - var(--colW) - var(--colW) - var(--colGap));
  --xOR: calc(100% - var(--edgePad) - var(--colW));

  --shaftY: var(--corniceH);
  --shaftEndY: calc(100% - var(--stepH));
  --shaftH2: calc(var(--shaftEndY) - var(--shaftY));

  background-image:
    repeating-linear-gradient(90deg, rgba(0,0,0,.06) 0 7px, rgba(255,255,255,.18) 7px 14px),
    repeating-linear-gradient(90deg, rgba(0,0,0,.06) 0 7px, rgba(255,255,255,.18) 7px 14px),
    repeating-linear-gradient(90deg, rgba(0,0,0,.06) 0 7px, rgba(255,255,255,.18) 7px 14px),
    repeating-linear-gradient(90deg, rgba(0,0,0,.06) 0 7px, rgba(255,255,255,.18) 7px 14px);

  background-size:
    var(--colW) var(--shaftH2),
