  overflow-x: hidden;
}

/* ====== CORNICE ====== */
body.publications-directory::after{
  content:"";
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: var(--corniceH);
  background:
    linear-gradient(180deg,#fff,rgba(0,0,0,.18));
  box-shadow: 0 4px 10px rgba(0,0,0,.25);
  z-index: 2;
}

/* ====== STAIRS ====== */
body.publications-directory::before{
  content:"";
  position: fixed;
  bottom: 0;
  left: 0;
  width: 100%;
  height: var(--stepH);
  background:
    repeating-linear-gradient(
      0deg,
      rgba(0,0,0,.08) 0 2px,
      rgba(255,255,255,.2) 2px 14px
    );
  z-index: 1;
}

/* ====== COLUMN SYSTEM ====== */
.portal{
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 1;
}

/* PAIR wrapper */
.pair{
  position: absolute;
  bottom: var(--stepH);
  display: flex;
  gap: var(--pairGap);
}

/* left / right placement */
.pair.left{ left: var(--pairInset); }
.pair.right{ right: var(--pairInset); }

/* ====== LOWER PLINTH (shared per pair) ====== */
.pair::before{
  content:"";
  position: absolute;
  bottom: 0;
  left: 50%;
  transform: translateX(-50%);
  width: var(--lowerPlinthW);
  height: var(--plinthH-lower);
  background: linear-gradient(180deg,#fff,var(--stone));
  border-radius: 999px;
  box-shadow: 0 6px 12px var(--shadow);
}

/* ====== COLUMN ====== */
.column{
  position: relative;
  width: var(--shaftW);
  height: calc(100dvh - var(--corniceH) - var(--stepH));
  display: flex;
  flex-direction: column;
  align-items: center;
}

