  bottom: 0;
  width: var(--upperPlinthW);
  height: var(--plinthH-upper);
  background: linear-gradient(180deg,#fff,var(--stone));
  border-radius: 999px;
  transform: translateY(-2px);
  box-shadow: 0 4px 8px var(--shadow);
}

